package com.skillsprint.controller.marketplace;
import com.skillsprint.common.ApiResponse; import com.skillsprint.dto.response.marketplace.*; import com.skillsprint.service.marketplace.MarketplaceWalletService; import java.util.*; import lombok.*; import lombok.experimental.FieldDefaults; import org.springframework.http.ResponseEntity; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.security.oauth2.jwt.Jwt; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/marketplace/wallet") @RequiredArgsConstructor @FieldDefaults(level=AccessLevel.PRIVATE,makeFinal=true)
public class MarketplaceWalletController { MarketplaceWalletService marketplaceWalletService; @GetMapping public ResponseEntity<ApiResponse<WalletBalanceResponse>> balance(@AuthenticationPrincipal Jwt jwt){return ResponseEntity.ok(ApiResponse.success(marketplaceWalletService.getBalance(jwt.getSubject())));} @GetMapping("/transactions") public ResponseEntity<ApiResponse<List<WalletTransactionResponse>>> transactions(@AuthenticationPrincipal Jwt jwt){return ResponseEntity.ok(ApiResponse.success(marketplaceWalletService.getTransactions(jwt.getSubject())));} }
